  1→import { useState, useMemo } from 'react';
  2→import { useParams } from 'react-router';
  3→import { useSession, useSessionMutation } from '@/hooks/useSessions';
  4→import { useInsights } from '@/hooks/useInsights';
  5→import { useMessages } from '@/hooks/useMessages';
  6→import {
  7→  getSessionTitle,
  8→  formatDuration,
  9→  formatDurationMinutes,
 10→  formatDateRange,
 11→  formatModelName,
 12→  cn,
 13→} from '@/lib/utils';
 14→import { SESSION_CHARACTER_COLORS, SESSION_CHARACTER_LABELS, SOURCE_TOOL_COLORS } from '@/lib/constants/colors';
 15→import { parseJsonField } from '@/lib/types';
 16→import { Badge } from '@/components/ui/badge';
 17→import { ErrorCard } from '@/components/ErrorCard';
 18→import { Button } from '@/components/ui/button';
 19→import { Skeleton } from '@/components/ui/skeleton';
 20→import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
 21→import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/components/ui/collapsible';
 22→import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip';
 23→import {
 24→  DropdownMenu,
 25→  DropdownMenuContent,
 26→  DropdownMenuItem,
 27→  DropdownMenuTrigger,
 28→} from '@/components/ui/dropdown-menu';
 29→import { InsightCard } from '@/components/insights/InsightCard';
 30→import { PromptQualityCard } from '@/components/insights/PromptQualityCard';
 31→import { AnalyzeDropdown } from '@/components/analysis/AnalyzeDropdown';
 32→import { RenameSessionDialog } from '@/components/sessions/RenameSessionDialog';
 33→import { ChatConversation } from '@/components/chat/conversation/ChatConversation';
 34→import {
 35→  MessageSquare,
 36→  Wrench,
 37→  Clock,
 38→  Pencil,
 39→  Sparkles,
 40→  X,
 41→  FileText,
 42→  BookOpen,
 43→  GitCommit,
 44→  BarChart2,
 45→  ChevronRight,
 46→  Cpu,
 47→} from 'lucide-react';
 48→import { toast } from 'sonner';
 49→
 50→export default function SessionDetailPage() {
 51→  const { id } = useParams<{ id: string }>();
 52→  const { data: session, isLoading: loading, error } = useSession(id);
 53→  const { data: insights = [] } = useInsights({ sessionId: id });
 54→  const messagesQuery = useMessages(id);
 55→  const sessionMutation = useSessionMutation();
 56→  const [renameOpen, setRenameOpen] = useState(false);
 57→  const [suggestedTitle, setSuggestedTitle] = useState<string | null>(null);
 58→
 59→  // Flatten paginated messages
 60→  const messages = messagesQuery.data?.pages.flat() ?? [];
 61→  const loadingMessages = messagesQuery.isLoading;
 62→  const loadingMore = messagesQuery.isFetchingNextPage;
 63→  const hasMore = messagesQuery.hasNextPage ?? false;
 64→
 65→  const allInsightIds = useMemo(() => new Set(insights.map((i) => i.id)), [insights]);
 66→
 67→  if (loading) {
 68→    return (
 69→      <div className="flex flex-col h-[calc(100vh-3.5rem)]">
 70→        <div className="shrink-0 border-b px-6 py-3 space-y-2">
 71→          <div className="flex items-center gap-2">
 72→            <Skeleton className="h-6 w-64" />
 73→            <Skeleton className="h-5 w-20 rounded-full" />
 74→          </div>
 75→          <div className="flex items-center gap-2">
 76→            <Skeleton className="h-3.5 w-20" />
 77→            <Skeleton className="h-3.5 w-20" />
 78→            <Skeleton className="h-3.5 w-20" />
 79→            <Skeleton className="h-3.5 w-32" />
 80→          </div>
 81→        </div>
 82→        <div className="p-6 space-y-6">
 83→          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
 84→            {[...Array(4)].map((_, i) => (
 85→              <div key={i} className="rounded-lg border px-3 py-2.5">
 86→                <Skeleton className="h-6 w-16 mx-auto" />
 87→                <Skeleton className="h-3 w-12 mx-auto mt-1" />
 88→              </div>
 89→            ))}
 90→          </div>
 91→          <div className="space-y-3">
 92→            {[...Array(3)].map((_, i) => (
 93→              <div key={i} className="rounded-lg border px-4 py-3 space-y-2">
 94→                <div className="flex items-center gap-2">
 95→                  <Skeleton className="h-5 w-20 rounded-full" />
 96→                  <Skeleton className="h-4 w-2/5" />
 97→                </div>
 98→                <Skeleton className="h-3.5 w-full" />
 99→                <Skeleton className="h-3.5 w-3/4" />
100→              </div>
101→            ))}
102→          </div>
103→        </div>
104→      </div>
105→    );
106→  }
107→
108→  if (error || !session) {
109→    return (
110→      <div className="p-6">
111→        <ErrorCard
112→          message={error instanceof Error ? error.message : 'Session not found'}
113→        />
114→      </div>
115→    );
116→  }
117→
118→  const nonPromptInsights = insights.filter(
119→    (i) => i.type !== 'prompt_quality' && i.type !== 'summary'
120→  );
121→  const hasPromptQuality = insights.some((i) => i.type === 'prompt_quality');
122→
123→  const summaryInsight = insights.find((i) => i.type === 'summary');
124→  const summaryText = session.summary || summaryInsight?.content;
125→  const summaryBulletsRaw = summaryInsight
126→    ? parseJsonField<string[]>(summaryInsight.bullets, [])
127→    : [];
128→  const summaryBullets =
129→    summaryBulletsRaw.length > 0
130→      ? summaryBulletsRaw
131→      : session.summary
132→        ? session.summary
133→            .split('\n')
134→            .filter((l) => l.startsWith('- '))
135→            .map((l) => l.slice(2))
136→        : [];
137→  const summaryTitle =
138→    summaryInsight?.title ||
139→    (session.summary
140→      ? session.summary.split('\n').find((l) => !l.startsWith('- '))?.trim() ||
141→        'Session Summary'
142→      : 'Session Summary');
143→
144→  const startedAt = new Date(session.started_at);
145→  const endedAt = new Date(session.ended_at);
146→  const durationMinutes = Math.round((endedAt.getTime() - startedAt.getTime()) / 60000);
147→  const characterColor = session.session_character
148→    ? SESSION_CHARACTER_COLORS[session.session_character]
149→    : null;
150→  const characterLabel = session.session_character
151→    ? SESSION_CHARACTER_LABELS[session.session_character]
152→    : null;
153→
154→  const modelsUsed = parseJsonField<string[]>(session.models_used, []);
155→
156→  function handleExport(format: 'plain' | 'obsidian' | 'notion') {
157→    const title = getSessionTitle(session!);
158→    const dateStr = startedAt.toISOString().slice(0, 10);
159→    const lines: string[] = [];
160→
161→    if (format === 'obsidian') {
162→      lines.push(`# ${title}`, '', `> [!info]`);
163→      lines.push(
164→        `> Date: ${dateStr}  `,
165→        `> Duration: ${formatDurationMinutes(durationMinutes)}  `,
166→        `> Project: ${session!.project_name}`
167→      );
168→    } else {
169→      lines.push(
170→        `# ${title}`,
171→        '',
172→        `**Date:** ${dateStr}  `,
173→        `**Duration:** ${formatDurationMinutes(durationMinutes)}  `,
174→        `**Project:** ${session!.project_name}`
175→      );
176→    }
177→
178→    if (summaryText) {
179→      lines.push('', '## Summary', '', summaryText);
180→    }
181→    if (insights.length > 0) {
182→      lines.push('', '## Insights');
183→      for (const insight of insights.filter((i) => i.type !== 'summary')) {
184→        lines.push('', `### ${insight.title} (${insight.type})`, '', insight.content);
185→      }
186→    }
187→
188→    const content = lines.join('\n');
189→    const projectSlug = session!.project_name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
190→    const filename = `session-${projectSlug}-${dateStr}.md`;
191→    const blob = new Blob([content], { type: 'text/markdown' });
192→    const url = URL.createObjectURL(blob);
193→    const a = document.createElement('a');
194→    a.href = url;
195→    a.download = filename;
196→    document.body.appendChild(a);
197→    a.click();
198→    document.body.removeChild(a);
199→    URL.revokeObjectURL(url);
200→    toast.success(`Exported as ${format === 'plain' ? 'Markdown' : format}`);
201→  }
202→
203→  return (
204→    <div className="flex flex-col h-[calc(100vh-3.5rem)]">
205→      {/* Compact header */}
206→      <div className="shrink-0 border-b px-6 py-3 space-y-2">
207→        {/* Row 1: Title + character badge + rename + analyze */}
208→        <div className="flex items-center gap-2 flex-wrap">
209→          <h1 className="text-lg font-semibold leading-tight">{getSessionTitle(session)}</h1>
210→          {characterLabel && characterColor && (
211→            <Badge variant="outline" className={cn('text-xs shrink-0', characterColor)}>
212→              {characterLabel}
213→            </Badge>
214→          )}
215→          <Tooltip>
216→            <TooltipTrigger asChild>
217→              <Button
218→                variant="ghost"
219→                size="icon"
220→                className="h-6 w-6 shrink-0"
221→                onClick={() => setRenameOpen(true)}
222→              >
223→                <Pencil className="h-3.5 w-3.5" />
224→                <span className="sr-only">Rename session</span>
225→              </Button>
226→            </TooltipTrigger>
227→            <TooltipContent side="bottom">Rename session</TooltipContent>
228→          </Tooltip>
229→          <div className="ml-auto flex items-center gap-1">
230→            <AnalyzeDropdown
231→              session={session}
232→              onTitleSuggestion={setSuggestedTitle}
233→              hasExistingInsights={nonPromptInsights.length > 0}
234→              insightCount={nonPromptInsights.length}
235→              hasExistingPromptQuality={hasPromptQuality}
236→            />
237→            <DropdownMenu>
238→              <Tooltip>
239→                <TooltipTrigger asChild>
240→                  <DropdownMenuTrigger asChild>
241→                    <Button variant="ghost" size="icon" className="h-7 w-7">
242→                      <FileText className="h-3.5 w-3.5" />
243→                      <span className="sr-only">Export session</span>
244→                    </Button>
245→                  </DropdownMenuTrigger>
246→                </TooltipTrigger>
247→                <TooltipContent side="bottom">Export session</TooltipContent>
248→              </Tooltip>
249→              <DropdownMenuContent align="end">
250→                <DropdownMenuItem onClick={() => handleExport('plain')}>
251→                  Export as Markdown
252→                </DropdownMenuItem>
253→                <DropdownMenuItem onClick={() => handleExport('obsidian')}>
254→                  Export for Obsidian
255→                </DropdownMenuItem>
256→                <DropdownMenuItem onClick={() => handleExport('notion')}>
257→                  Export for Notion
258→                </DropdownMenuItem>
259→              </DropdownMenuContent>
260→            </DropdownMenu>
261→          </div>
262→        </div>
263→
264→        {/* Row 2: Metadata */}
265→        <div className="flex items-center gap-2 text-xs text-muted-foreground flex-wrap">
266→          <MessageSquare className="h-3.5 w-3.5" />
267→          <span>{session.message_count} messages</span>
268→          <span>·</span>
269→          <Wrench className="h-3.5 w-3.5" />
270→          <span>{session.tool_call_count} tools</span>
271→          <span>·</span>
272→          <Clock className="h-3.5 w-3.5" />
273→          <span>{formatDuration(startedAt, endedAt)}</span>
274→          <span>·</span>
275→          <span>{formatDateRange(startedAt, endedAt)}</span>
276→          <span>·</span>
277→          {session.git_remote_url ? (
278→            <a
279→              href={session.git_remote_url}
280→              target="_blank"
281→              rel="noopener noreferrer"
282→              className="hover:text-foreground underline-offset-2 hover:underline"
283→            >
284→              {session.project_name}
285→            </a>
286→          ) : (
287→            <span>{session.project_name}</span>
288→          )}
289→          {session.source_tool && session.source_tool !== 'claude-code' && (
290→            <>
291→              <span>·</span>
292→              <Badge
293→                variant="outline"
294→                className={cn(
295→                  'text-xs capitalize',
296→                  SOURCE_TOOL_COLORS[session.source_tool] ?? 'bg-muted text-muted-foreground'
297→                )}
298→              >
299→                {session.source_tool}
300→              </Badge>
301→            </>
302→          )}
303→        </div>
304→      </div>
305→
306→      {/* AI Title Suggestion Banner */}
307→      {suggestedTitle && suggestedTitle !== getSessionTitle(session) && (
308→        <div className="shrink-0 flex items-center justify-between gap-4 px-6 py-2.5 border-b bg-muted/50">
309→          <div className="flex items-center gap-2">
310→            <Sparkles className="h-4 w-4 text-purple-500" />
311→            <span className="text-sm">
312→              AI suggests: <span className="font-medium">"{suggestedTitle}"</span>
313→            </span>
314→          </div>
315→          <div className="flex items-center gap-2">
316→            <Button
317→              size="sm"
318→              onClick={async () => {
319→                try {
320→                  await sessionMutation.mutateAsync({
321→                    id: session.id,
322→                    customTitle: suggestedTitle!,
323→                  });
324→                  toast.success('Session renamed successfully');
325→                  setSuggestedTitle(null);
326→                } catch (err) {
327→                  toast.error(
328→                    err instanceof Error ? err.message : 'Failed to rename session'
329→                  );
330→                }
331→              }}
332→            >
333→              Apply
334→            </Button>
335→            <Button
336→              size="sm"
337→              variant="ghost"
338→              onClick={() => setSuggestedTitle(null)}
339→              aria-label="Dismiss suggestion"
340→            >
341→              <X className="h-4 w-4" />
342→            </Button>
343→          </div>
344→        </div>
345→      )}
346→
347→      {/* Tabs */}
348→      <Tabs defaultValue="overview" className="flex flex-col flex-1 overflow-hidden">
349→        <TabsList className="shrink-0 bg-transparent border-b rounded-none h-auto w-full justify-start gap-4 px-6">
350→          <TabsTrigger
351→            value="overview"
352→            className="relative h-10 rounded-none border-b-2 border-transparent bg-transparent px-0 pb-3 pt-2 font-medium text-muted-foreground shadow-none data-[state=active]:border-foreground data-[state=active]:text-foreground data-[state=active]:shadow-none"
353→          >
354→            Overview
355→          </TabsTrigger>
356→          <TabsTrigger
357→            value="conversation"
358→            className="relative h-10 rounded-none border-b-2 border-transparent bg-transparent px-0 pb-3 pt-2 font-medium text-muted-foreground shadow-none data-[state=active]:border-foreground data-[state=active]:text-foreground data-[state=active]:shadow-none"
359→          >
360→            Conversation ({session.message_count})
361→          </TabsTrigger>
362→        </TabsList>
363→
364→        <TabsContent value="overview" className="flex-1 overflow-y-auto mt-0 p-6 space-y-6">
365→          {/* Summary */}
366→          {summaryText && (
367→            <div>
368→              <div className="flex items-center gap-2 mb-2">
369→                <FileText className="h-4 w-4 text-purple-500 shrink-0" />
370→                <h3 className="text-sm font-medium">Summary</h3>
371→              </div>
372→              <div className="rounded-md bg-muted/20 px-4 py-3">
373→                <p className="font-medium text-sm mb-1.5">{summaryTitle}</p>
374→                {summaryBullets.length > 0 ? (
375→                  <ul className="list-disc list-inside space-y-0.5 text-sm text-muted-foreground">
376→                    {summaryBullets.map((bullet, i) => (
377→                      <li key={i}>{bullet}</li>
378→                    ))}
379→                  </ul>
380→                ) : (
381→                  <p className="text-sm text-muted-foreground">{summaryText}</p>
382→                )}
383→              </div>
384→            </div>
385→          )}
386→
387→          {/* Session Vitals */}
388→          <div>
389→            <h3 className="text-sm font-medium mb-2">Session Vitals</h3>
390→            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
391→              <div className="rounded-lg border bg-muted/20 px-3 py-2.5 text-center">
392→                <div className="text-lg font-semibold">
393→                  {formatDurationMinutes(durationMinutes)}
394→                </div>
395→                <div className="text-xs text-muted-foreground mt-0.5">Duration</div>
396→              </div>
397→              <div className="rounded-lg border bg-muted/20 px-3 py-2.5 text-center">
398→                <div className="text-lg font-semibold">{session.message_count}</div>
399→                <div className="text-xs text-muted-foreground mt-0.5">Messages</div>
400→              </div>
401→              <div className="rounded-lg border bg-muted/20 px-3 py-2.5 text-center">
402→                <div className="text-lg font-semibold">{session.tool_call_count}</div>
403→                <div className="text-xs text-muted-foreground mt-0.5">Tool calls</div>
404→              </div>
405→              <div className="rounded-lg border bg-muted/20 px-3 py-2.5 text-center">
406→                {characterLabel && characterColor ? (
407→                  <>
408→                    <div
409→                      className={cn(
410→                        'text-sm font-semibold',
411→                        characterColor.split(' ').find((c) => c.startsWith('text-'))
412→                      )}
413→                    >
414→                      {characterLabel}
415→                    </div>
416→                    <div className="text-xs text-muted-foreground mt-0.5">Character</div>
417→                  </>
418→                ) : (
419→                  <>
420→                    <div className="text-sm font-semibold text-muted-foreground">—</div>
421→                    <div className="text-xs text-muted-foreground mt-0.5">Character</div>
422→                  </>
423→                )}
424→              </div>
425→            </div>
426→          </div>
427→
428→          {/* Usage Stats */}
429→          {session.total_input_tokens != null && (
430→            <div>
431→              <Collapsible>
432→                <CollapsibleTrigger className="flex items-center gap-2 text-sm font-medium group w-full">
433→                  <ChevronRight className="h-4 w-4 transition-transform group-data-[state=open]:rotate-90" />
434→                  <Cpu className="h-4 w-4 text-muted-foreground" />
435→                  Usage Stats
436→                  {session.estimated_cost_usd != null && (
437→                    <span className="text-muted-foreground font-normal ml-1">
438→                      (${session.estimated_cost_usd.toFixed(2)})
439→                    </span>
440→                  )}
441→                </CollapsibleTrigger>
442→                <CollapsibleContent className="pl-6 pt-3">
443→                  <div className="rounded-lg border bg-muted/20 p-4 space-y-2 text-sm">
444→                    <div className="flex justify-between">
445→                      <span className="text-muted-foreground">Input tokens</span>
446→                      <span>{session.total_input_tokens?.toLocaleString()}</span>
447→                    </div>
448→                    <div className="flex justify-between">
449→                      <span className="text-muted-foreground">Output tokens</span>
450→                      <span>{session.total_output_tokens?.toLocaleString()}</span>
451→                    </div>
452→                    {(session.cache_read_tokens ?? 0) > 0 && (
453→                      <div className="flex justify-between">
454→                        <span className="text-muted-foreground">Cache read tokens</span>
455→                        <span>{session.cache_read_tokens?.toLocaleString()}</span>
456→                      </div>
457→                    )}
458→                    {(session.cache_creation_tokens ?? 0) > 0 && (
459→                      <div className="flex justify-between">
460→                        <span className="text-muted-foreground">Cache creation tokens</span>
461→                        <span>{session.cache_creation_tokens?.toLocaleString()}</span>
462→                      </div>
463→                    )}
464→                    <div className="flex justify-between font-medium pt-2 border-t">
465→                      <span>Estimated cost</span>
466→                      <span>${session.estimated_cost_usd?.toFixed(4)}</span>
467→                    </div>
468→                    {modelsUsed.length > 0 && (
469→                      <div className="flex justify-between pt-1">
470→                        <span className="text-muted-foreground">Models</span>
471→                        <span>{modelsUsed.map(formatModelName).join(', ')}</span>
472→                      </div>
473→                    )}
474→                  </div>
475→                </CollapsibleContent>
476→              </Collapsible>
477→            </div>
478→          )}
479→
480→          {/* Insights */}
481→          {insights.filter((i) => i.type !== 'summary').length === 0 ? (
482→            <div className="rounded-lg border border-dashed">
483→              <div className="flex flex-col items-center justify-center py-12 text-center space-y-3">
484→                <BarChart2 className="h-8 w-8 text-muted-foreground" />
485→                <p className="font-medium text-sm">This session hasn't been analyzed yet</p>
486→                <p className="text-xs text-muted-foreground">
487→                  Generate AI insights to extract learnings, decisions, and a session summary.
488→                </p>
489→                <div className="pt-2">
490→                  <AnalyzeDropdown
491→                    session={session}
492→                    onTitleSuggestion={setSuggestedTitle}
493→                    hasExistingInsights={false}
494→                    insightCount={0}
495→                    hasExistingPromptQuality={false}
496→                  />
497→                </div>
498→              </div>
499→            </div>
500→          ) : (
501→            <>
502→              {insights
503→                .filter((i) => i.type === 'prompt_quality')
504→                .map((insight) => (
505→                  <PromptQualityCard key={insight.id} insight={insight} />
506→                ))}
507→
508→              {(() => {
509→                const learningInsights = insights.filter(
510→                  (i) => i.type === 'learning' || i.type === 'technique'
511→                );
512→                if (learningInsights.length === 0) return null;
513→                return (
514→                  <div>
515→                    <div className="flex items-center gap-2 mb-3">
516→                      <BookOpen className="h-4 w-4 text-muted-foreground" />
517→                      <h3 className="text-sm font-medium">Learnings</h3>
518→                      <Badge variant="secondary" className="text-xs">
519→                        {learningInsights.length}
520→                      </Badge>
521→                    </div>
522→                    <div className="space-y-3">
523→                      {learningInsights.map((insight) => (
524→                        <InsightCard
525→                          key={insight.id}
526→                          insight={insight}
527→                          showProject={false}
528→                          allInsightIds={allInsightIds}
529→                        />
530→                      ))}
531→                    </div>
532→                  </div>
533→                );
534→              })()}
535→
536→              {(() => {
537→                const decisionInsights = insights.filter((i) => i.type === 'decision');
538→                if (decisionInsights.length === 0) return null;
539→                return (
540→                  <div>
541→                    <div className="flex items-center gap-2 mb-3">
542→                      <GitCommit className="h-4 w-4 text-muted-foreground" />
543→                      <h3 className="text-sm font-medium">Decisions</h3>
544→                      <Badge variant="secondary" className="text-xs">
545→                        {decisionInsights.length}
546→                      </Badge>
547→                    </div>
548→                    <div className="space-y-3">
549→                      {decisionInsights.map((insight) => (
550→                        <InsightCard
551→                          key={insight.id}
552→                          insight={insight}
553→                          showProject={false}
554→                          allInsightIds={allInsightIds}
555→                        />
556→                      ))}
557→                    </div>
558→                  </div>
559→                );
560→              })()}
561→            </>
562→          )}
563→        </TabsContent>
564→
565→        <TabsContent
566→          value="conversation"
567→          className="flex-1 overflow-y-auto mt-0 bg-muted/40 dark:bg-muted/20"
568→        >
569→          <ChatConversation
570→            messages={messages}
571→            loading={loadingMessages}
572→            loadingMore={loadingMore}
573→            hasMore={hasMore}
574→            onLoadMore={() => messagesQuery.fetchNextPage()}
575→            sourceTool={session.source_tool}
576→          />
577→        </TabsContent>
