301→export interface RecurringInsightGroup {
302→  insightIds: string[];
303→  theme: string;
304→}
305→
306→export interface RecurringInsightResult {
307→  success: boolean;
308→  groups: RecurringInsightGroup[];
309→  updatedCount: number;
310→  error?: string;
311→  usage?: {
312→    inputTokens: number;
313→    outputTokens: number;
314→  };
315→}
