645→/**
646→ * Write insight rows to SQLite using prepared statements.
647→ */
648→function saveInsightsToDb(insights: InsightRow[]): void {
649→  const db = getDb();
650→  const insert = db.prepare(`
651→    INSERT OR REPLACE INTO insights (
652→      id, session_id, project_id, project_name, type, title, content,
653→      summary, bullets, confidence, source, metadata, timestamp,
654→      created_at, scope, analysis_version
655→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
656→  `);
657→
658→  const insertMany = db.transaction((rows: InsightRow[]) => {
659→    for (const row of rows) {
660→      insert.run(
661→        row.id,
662→        row.session_id,
663→        row.project_id,
664→        row.project_name,
665→        row.type,
666→        row.title,
667→        row.content,
668→        row.summary,
669→        row.bullets,
670→        row.confidence,
671→        row.source,
672→        row.metadata,
673→        row.timestamp,
674→        row.created_at,
675→        row.scope,
676→        row.analysis_version,
677→      );
678→    }
679→  });
680→
681→  insertMany(insights);
682→}
