 25→interface AnalyzeDropdownProps {
 26→  session: Session;
 27→  onTitleSuggestion?: (title: string) => void;
 28→  hasExistingInsights?: boolean;
 29→  insightCount?: number;
 30→  hasExistingPromptQuality?: boolean;
 31→}
 32→
 33→export function AnalyzeDropdown({
 34→  session,
 35→  hasExistingInsights,
 36→  insightCount,
 37→  hasExistingPromptQuality,
 38→}: AnalyzeDropdownProps) {
 39→  const [confirmSessionOpen, setConfirmSessionOpen] = useState(false);
 40→  const [confirmPromptOpen, setConfirmPromptOpen] = useState(false);
 41→  const { state: analysisState, startAnalysis, cancelAnalysis } = useAnalysis();
 42→  const { data: llmConfig } = useLlmConfig();
 43→
 44→  const configured = !!(llmConfig?.provider && llmConfig?.model);
 45→
 46→  const isAnalyzingThisSession =
 47→    analysisState.status === 'analyzing' && analysisState.sessionId === session.id;
 48→  const isAnalyzingOther =
 49→    analysisState.status === 'analyzing' && analysisState.sessionId !== session.id;
 50→  const isCompleteForSession =
 51→    analysisState.status === 'complete' &&
 52→    analysisState.sessionId === session.id &&
 53→    analysisState.type === 'session';
 54→
 55→  const handleSessionAnalyze = () => {
 56→    startAnalysis(session, 'session');
 57→  };
 58→
 59→  const handlePromptAnalyze = () => {
 60→    startAnalysis(session, 'prompt_quality');
 61→  };
 62→
 63→  const handleSessionClick = () => {
 64→    if (hasExistingInsights && !isCompleteForSession) {
 65→      setConfirmSessionOpen(true);
 66→    } else {
 67→      handleSessionAnalyze();
 68→    }
 69→  };
 70→
 71→  const handlePromptClick = () => {
 72→    const isCompleteForPrompt =
 73→      analysisState.status === 'complete' &&
 74→      analysisState.sessionId === session.id &&
 75→      analysisState.type === 'prompt_quality';
 76→
 77→    if (hasExistingPromptQuality && !isCompleteForPrompt) {
 78→      setConfirmPromptOpen(true);
 79→    } else {
 80→      handlePromptAnalyze();
 81→    }
 82→  };
 83→
 84→  if (!configured) {
 85→    return (
 86→      <Link
 87→        to="/settings"
 88→        className="text-xs text-muted-foreground underline hover:text-foreground"
 89→      >
 90→        Configure AI in Settings
 91→      </Link>
 92→    );
 93→  }
 94→
 95→  if (isAnalyzingThisSession) {
