23→function RouteEffects() {
24→  const { pathname } = useLocation();
25→
26→  // Scroll to top on route change
27→  useEffect(() => {
28→    window.scrollTo(0, 0);
29→  }, [pathname]);
30→
31→  // Update document.title per route
32→  useEffect(() => {
33→    const segment = '/' + pathname.split('/')[1];
34→    const page = ROUTE_TITLES[segment];
35→    document.title = page ? `${page} — Code Insights` : 'Code Insights';
36→  }, [pathname]);
37→
38→  return null;
39→}
