@@ -0,0 +1,99 @@
+'use client';
+
+import { useState } from 'react';
+import { Target, Loader2, AlertCircle, CheckCircle } from 'lucide-react';
+import { Button } from '@/components/ui/button';
+import { isLLMConfigured, analyzePromptQuality } from '@/lib/llm';
+import { useMessages } from '@/lib/hooks/useFirestore';
+import type { Session } from '@/lib/types';
+
+interface AnalyzePromptQualityButtonProps {
+  session: Session;
+}
+
+export function AnalyzePromptQualityButton({ session }: AnalyzePromptQualityButtonProps) {
+  const [analyzing, setAnalyzing] = useState(false);
+  const [error, setError] = useState<string | null>(null);
+  const [success, setSuccess] = useState(false);
+  const [usage, setUsage] = useState<{ inputTokens: number; outputTokens: number } | null>(null);
+
+  const { messages, loading: messagesLoading } = useMessages(session.id);
+  const configured = isLLMConfigured();
+
+  const handleAnalyze = async () => {
+    if (!configured) return;
+
+    setAnalyzing(true);
+    setError(null);
+    setSuccess(false);
+    setUsage(null);
+
+    const result = await analyzePromptQuality(session, messages);
+
+    if (result.success) {
+      setSuccess(true);
+      if (result.usage) {
+        setUsage(result.usage);
+      }
+    } else {
+      setError(result.error || 'Analysis failed');
+    }
+
+    setAnalyzing(false);
+  };
+
+  if (!configured) {
+    return null; // The main AnalyzeButton already shows the config prompt
+  }
+
+  if (messagesLoading || messages.length === 0) {
+    return null; // Let the main AnalyzeButton handle these states
+  }
+
+  const userMessageCount = messages.filter((m) => m.type === 'user').length;
+  if (userMessageCount < 2) {
+    return null; // Not enough user messages
+  }
+
+  return (
+    <div className="space-y-2">
+      <Button
+        onClick={handleAnalyze}
+        disabled={analyzing}
+        variant={success ? 'outline' : 'secondary'}
+        size="sm"
+        className="gap-2"
+      >
+        {analyzing ? (
+          <>
+            <Loader2 className="h-3.5 w-3.5 animate-spin" />
+            Analyzing prompts...
+          </>
+        ) : success ? (
+          <>
+            <CheckCircle className="h-3.5 w-3.5 text-green-500" />
+            Re-analyze Prompts
+          </>
+        ) : (
+          <>
+            <Target className="h-3.5 w-3.5" />
+            Analyze Prompt Quality
+          </>
+        )}
+      </Button>
+
+      {error && (
+        <div className="flex items-start gap-2 text-sm text-red-500">
+          <AlertCircle className="h-4 w-4 mt-0.5 shrink-0" />
+          <span>{error}</span>
+        </div>
+      )}
+
+      {success && usage && (
+        <p className="text-xs text-muted-foreground">
+          ({usage.inputTokens.toLocaleString()} input / {usage.outputTokens.toLocaleString()} output tokens)
+        </p>
+      )}
+    </div>
+  );
+}
