+/**
+ * Analyze prompt quality for a session
+ */
+export async function analyzePromptQuality(
+  session: Session,
+  messages: Message[]
+): Promise<AnalysisResult> {
+  if (!isLLMConfigured()) {
+    return {
+      success: false,
+      insights: [],
+      error: 'LLM not configured. Go to Settings to configure an AI provider.',
+    };
+  }
+
+  if (messages.length === 0) {
+    return {
+      success: false,
+      insights: [],
+      error: 'No messages found for this session. Run `code-insights sync` to upload messages.',
+    };
+  }
+
+  const userMessages = messages.filter((m) => m.type === 'user');
+  if (userMessages.length < 2) {
+    return {
+      success: false,
+      insights: [],
+      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
+    };
+  }
+
+  try {
+    const client = createLLMClient();
+    const formattedMessages = formatMessagesForAnalysis(messages);
+
+    // Truncate if too long
+    let analysisInput = formattedMessages;
+    const estimatedTokens = client.estimateTokens(formattedMessages);
+    if (estimatedTokens > MAX_INPUT_TOKENS) {
+      // Take first 80% of the token budget worth of messages
+      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
+      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
+    }
+
+    const prompt = generatePromptQualityPrompt(
+      session.projectName,
+      analysisInput,
+      messages.length
+    );
+
+    const response = await client.chat([
+      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
+      { role: 'user', content: prompt },
+    ]);
+
+    const parsed = parsePromptQualityResponse(response.content);
+    if (!parsed) {
+      return {
+        success: false,
+        insights: [],
+        error: 'Failed to parse prompt quality analysis. Please try again.',
+      };
+    }
+
+    const insight = convertPromptQualityToInsight(parsed, session);
+
+    // Delete existing prompt_quality insights for this session, then save the new one
+    await deletePromptQualityInsights(session.id);
+    await saveInsights([insight]);
+
+    return {
+      success: true,
+      insights: [insight],
+      usage: response.usage ? {
+        inputTokens: response.usage.inputTokens,
+        outputTokens: response.usage.outputTokens,
+      } : undefined,
+    };
+  } catch (error) {
+    return {
+      success: false,
+      insights: [],
+      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
+    };
+  }
+}
+
+/**
+ * Convert prompt quality response to an Insight object
+ */
+function convertPromptQualityToInsight(response: PromptQualityResponse, session: Session): Insight {
+  const projectId = generateProjectId(session.projectPath);
+
+  return {
+    id: generateInsightId(),
+    sessionId: session.id,
+    projectId,
+    projectName: session.projectName,
+    type: 'prompt_quality' as InsightType,
+    title: `Prompt Efficiency: ${response.efficiencyScore}/100`,
+    content: response.overallAssessment,
+    summary: response.overallAssessment,
+    bullets: response.tips,
+    confidence: 0.85,
+    source: 'llm',
+    metadata: {
+      efficiencyScore: response.efficiencyScore,
+      wastedTurns: response.wastedTurns,
+      antiPatterns: response.antiPatterns,
+      potentialMessageReduction: response.potentialMessageReduction,
+    },
+    timestamp: session.endedAt,
+    createdAt: new Date(),
+    scope: 'session',
+    analysisVersion: ANALYSIS_VERSION,
+  };
+}
+
+/**
+ * Delete existing prompt_quality insights for a session
+ */
+async function deletePromptQualityInsights(sessionId: string): Promise<void> {
+  const { getDb, isFirebaseInitialized } = await import('../firebase');
+  const { collection, query, where, getDocs, writeBatch } = await import('firebase/firestore');
+
+  if (!isFirebaseInitialized()) return;
+
+  const db = getDb();
+  const q = query(
+    collection(db, 'insights'),
+    where('sessionId', '==', sessionId),
+    where('type', '==', 'prompt_quality')
+  );
+  const snapshot = await getDocs(q);
+  if (snapshot.empty) return;
+
+  const batch = writeBatch(db);
+  for (const docSnap of snapshot.docs) {
+    batch.delete(docSnap.ref);
+  }
+  await batch.commit();
+}
