+'use client';
+
+import { useState } from 'react';
+import { Link2, Loader2, AlertCircle, CheckCircle } from 'lucide-react';
+import { Button } from '@/components/ui/button';
+import { isLLMConfigured } from '@/lib/llm';
+import { findRecurringInsights } from '@/lib/llm/analysis';
+import type { Insight } from '@/lib/types';
+
+interface FindRecurringButtonProps {
+  insights: Insight[];
+}
+
+export function FindRecurringButton({ insights }: FindRecurringButtonProps) {
+  const [analyzing, setAnalyzing] = useState(false);
+  const [error, setError] = useState<string | null>(null);
+  const [result, setResult] = useState<{ groups: number; updated: number } | null>(null);
+
+  const configured = isLLMConfigured();
+  const candidates = insights.filter(i => i.type !== 'summary' && i.type !== 'prompt_quality');
+
+  if (!configured) {
+    return null; // Don't show button if LLM not configured
+  }
+
+  if (candidates.length < 2) {
+    return null; // Not enough insights to compare
+  }
+
+  const handleFind = async () => {
+    setAnalyzing(true);
+    setError(null);
+    setResult(null);
+
+    const res = await findRecurringInsights(insights);
+
+    if (res.success) {
+      setResult({ groups: res.groups.length, updated: res.updatedCount });
+    } else {
+      setError(res.error || 'Analysis failed');
+    }
+
+    setAnalyzing(false);
+  };
+
+  return (
+    <div className="flex items-center gap-3">
+      <Button
+        onClick={handleFind}
+        disabled={analyzing}
+        variant="outline"
+        className="gap-2"
+      >
+        {analyzing ? (
+          <>
+            <Loader2 className="h-4 w-4 animate-spin" />
+            Finding patterns...
+          </>
+        ) : result ? (
+          <>
+            <CheckCircle className="h-4 w-4 text-green-500" />
+            Find Again
+          </>
+        ) : (
+          <>
+            <Link2 className="h-4 w-4" />
+            Find Recurring Insights
+          </>
+        )}
+      </Button>
+
+      {error && (
+        <span className="text-sm text-red-500 flex items-center gap-1">
+          <AlertCircle className="h-3 w-3" />
+          {error}
+        </span>
+      )}
+
+      {result && (
+        <span className="text-sm text-green-600">
+          {result.groups > 0
+            ? `Found ${result.groups} recurring pattern${result.groups > 1 ? 's' : ''} across ${result.updated} insights`
+            : 'No recurring patterns found'}
+        </span>
+      )}
+    </div>
+  );
+}
