 }
+
+/**
+ * Update linked insights (bidirectional links for recurring detection)
+ */
+export async function updateInsightLinks(
+  links: Array<{ insightId: string; linkedIds: string[] }>
+): Promise<void> {
+  if (!isFirebaseInitialized() || links.length === 0) return;
+
+  const db = getDb();
+  const batches: ReturnType<typeof writeBatch>[] = [];
+  let currentBatch = writeBatch(db);
+  let operationCount = 0;
+
+  for (const { insightId, linkedIds } of links) {
+    const ref = doc(db, 'insights', insightId);
+    currentBatch.set(ref, { linkedInsightIds: linkedIds }, { merge: true });
+    operationCount++;
+
+    if (operationCount >= 500) {
+      batches.push(currentBatch);
+      currentBatch = writeBatch(db);
+      operationCount = 0;
+    }
+  }
+
+  if (operationCount > 0) {
+    batches.push(currentBatch);
+  }
+
+  await Promise.all(batches.map((batch) => batch.commit()));
+}
