+
+export interface RecurringInsightGroup {
+  insightIds: string[];
+  theme: string;  // LLM's description of what these insights share
+}
+
+export interface RecurringInsightResult {
+  success: boolean;
+  groups: RecurringInsightGroup[];
+  updatedCount: number;
+  error?: string;
+  usage?: {
+    inputTokens: number;
+    outputTokens: number;
+  };
+}
+
+export async function findRecurringInsights(
+  insights: Insight[]
+): Promise<RecurringInsightResult> {
+  if (!isLLMConfigured()) {
+    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
+  }
+
+  // Filter to non-summary insights only, cap at 200
+  const candidates = insights
+    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
+    .slice(0, 200);
+
+  if (candidates.length < 2) {
+    return { success: false, groups: [], updatedCount: 0, error: 'Need at least 2 non-summary insights to find patterns.' };
+  }
+
+  try {
+    const client = createLLMClient();
+
+    // Build compact representation for LLM
+    const insightData = candidates.map(i => ({
+      id: i.id,
+      type: i.type,
+      title: i.title,
+      summary: i.summary.slice(0, 150),
+      projectName: i.projectName,
+      sessionId: i.sessionId,
+    }));
+
+    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning, decision, or technique even if worded differently.
+
+Each insight has an id, type, title, summary, projectName, and sessionId.
+
+RULES:
+- Only group insights that are genuinely about the same concept/topic
+- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
+- A group must have at least 2 insights
+- An insight can only belong to one group
+- Provide a brief "theme" describing what the group shares
+- If no recurring patterns exist, return an empty groups array
+
+INSIGHTS:
+${JSON.stringify(insightData, null, 2)}
+
+Respond with valid JSON only:
+{
+  "groups": [
+    {
+      "insightIds": ["insight_abc", "insight_def"],
+      "theme": "Brief description of the shared concept"
+    }
+  ]
+}`;
+
+    const response = await client.chat([
+      { role: 'system', content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.' },
+      { role: 'user', content: prompt },
+    ]);
+
+    // Parse response
+    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
+    if (!jsonMatch) {
+      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
+    }
+
+    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
+    const groups = parsed.groups || [];
+
+    // Validate: filter out groups with < 2 insights or invalid IDs
+    const validIds = new Set(candidates.map(i => i.id));
+    const validGroups = groups
+      .map(g => ({
+        ...g,
+        insightIds: g.insightIds.filter(id => validIds.has(id)),
+      }))
+      .filter(g => g.insightIds.length >= 2);
+
+    if (validGroups.length === 0) {
+      return {
+        success: true,
+        groups: [],
+        updatedCount: 0,
+        usage: response.usage ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens } : undefined,
+      };
+    }
+
+    // Build bidirectional links
+    const linkMap = new Map<string, string[]>();
+    for (const group of validGroups) {
+      for (const id of group.insightIds) {
+        const others = group.insightIds.filter(otherId => otherId !== id);
+        const existing = linkMap.get(id) || [];
+        linkMap.set(id, [...new Set([...existing, ...others])]);
+      }
+    }
+
+    // Update Firestore with bidirectional links
+    const linkUpdates = Array.from(linkMap.entries()).map(([insightId, linkedIds]) => ({
+      insightId,
+      linkedIds,
+    }));
+
+    await updateInsightLinks(linkUpdates);
+
+    return {
+      success: true,
+      groups: validGroups,
+      updatedCount: linkUpdates.length,
+      usage: response.usage ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens } : undefined,
+    };
+  } catch (error) {
+    return {
+      success: false,
+      groups: [],
+      updatedCount: 0,
+      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
+    };
+  }
+}
