 16→
 17→interface BulkAnalyzeButtonProps {
 18→  sessions: Session[];
 19→  onComplete?: () => void;
 20→}
 21→
 22→export function BulkAnalyzeButton({ sessions, onComplete }: BulkAnalyzeButtonProps) {
 23→  const [open, setOpen] = useState(false);
 24→  const [analyzing, setAnalyzing] = useState(false);
 25→  const [progress, setProgress] = useState({ completed: 0, total: 0 });
 26→  const [result, setResult] = useState<{
 27→    successful: number;
 28→    failed: number;
 29→    errors: string[];
 30→  } | null>(null);
 31→  const { data: llmConfig } = useLlmConfig();
 32→  const queryClient = useQueryClient();
 33→
 34→  const configured = !!(llmConfig?.provider && llmConfig?.model);
 35→
 36→  const handleAnalyze = async () => {
 37→    if (!configured || sessions.length === 0) return;
 38→
 39→    setAnalyzing(true);
 40→    setProgress({ completed: 0, total: sessions.length });
 41→    setResult(null);
 42→
 43→    let successful = 0;
 44→    let failed = 0;
 45→    const errors: string[] = [];
 46→
 47→    for (const session of sessions) {
 48→      try {
 49→        await analyzeSession(session.id);
 50→        successful++;
 51→      } catch (error) {
 52→        failed++;
 53→        errors.push(error instanceof Error ? error.message : `Failed: ${session.id}`);
 54→      }
 55→      setProgress((prev) => ({ ...prev, completed: prev.completed + 1 }));
 56→    }
 57→
