  1→import { Hono } from 'hono';
  2→import { getDb } from '@code-insights/cli/db/client';
  3→import { trackEvent } from '@code-insights/cli/utils/telemetry';
  4→import { parseIntParam } from '../utils.js';
  5→import { analyzeSession, analyzePromptQuality, findRecurringInsights } from '../llm/analysis.js';
  6→import { isLLMConfigured } from '../llm/client.js';
  7→import type { SQLiteMessageRow, SessionData } from '../llm/analysis.js';
  8→
  9→const app = new Hono();
 10→
 11→// POST /api/analysis/session
 12→// Body: { sessionId: string }
 13→// Fetches session + messages from SQLite, runs LLM analysis, saves insights, returns results.
 14→app.post('/session', async (c) => {
 15→  if (!isLLMConfigured()) {
 16→    return c.json({
 17→      success: false,
 18→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 19→    }, 400);
 20→  }
 21→
 22→  const body = await c.req.json<{ sessionId?: string }>();
 23→  if (!body.sessionId || typeof body.sessionId !== 'string') {
 24→    return c.json({ error: 'Missing required field: sessionId' }, 400);
 25→  }
 26→
 27→  const db = getDb();
 28→
 29→  const session = db.prepare(`
 30→    SELECT id, project_id, project_name, project_path, summary, ended_at
 31→    FROM sessions WHERE id = ?
 32→  `).get(body.sessionId) as SessionData | undefined;
 33→
 34→  if (!session) {
 35→    return c.json({ error: 'Session not found' }, 404);
 36→  }
 37→
 38→  const messages = db.prepare(`
 39→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
 40→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
 41→  `).all(body.sessionId) as SQLiteMessageRow[];
 42→
 43→  const result = await analyzeSession(session, messages);
 44→  if (result.success) trackEvent('analysis', true, 'session');
 45→  return c.json(result, result.success ? 200 : 422);
 46→});
 47→
 48→// POST /api/analysis/prompt-quality
 49→// Body: { sessionId: string }
 50→// Runs prompt quality analysis on user messages in the session.
 51→app.post('/prompt-quality', async (c) => {
 52→  if (!isLLMConfigured()) {
 53→    return c.json({
 54→      success: false,
 55→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 56→    }, 400);
 57→  }
 58→
 59→  const body = await c.req.json<{ sessionId?: string }>();
 60→  if (!body.sessionId || typeof body.sessionId !== 'string') {
 61→    return c.json({ error: 'Missing required field: sessionId' }, 400);
 62→  }
 63→
 64→  const db = getDb();
 65→
 66→  const session = db.prepare(`
 67→    SELECT id, project_id, project_name, project_path, summary, ended_at
 68→    FROM sessions WHERE id = ?
 69→  `).get(body.sessionId) as SessionData | undefined;
 70→
 71→  if (!session) {
 72→    return c.json({ error: 'Session not found' }, 404);
 73→  }
 74→
 75→  const messages = db.prepare(`
 76→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
 77→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
 78→  `).all(body.sessionId) as SQLiteMessageRow[];
 79→
 80→  const result = await analyzePromptQuality(session, messages);
 81→  if (result.success) trackEvent('analysis', true, 'prompt-quality');
 82→  return c.json(result, result.success ? 200 : 422);
 83→});
 84→
 85→// POST /api/analysis/recurring
 86→// Body: { projectId?: string; limit?: number }
 87→// Finds recurring insight patterns across sessions.
 88→app.post('/recurring', async (c) => {
 89→  if (!isLLMConfigured()) {
 90→    return c.json({
 91→      success: false,
 92→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 93→    }, 400);
 94→  }
 95→
 96→  const body = await c.req.json<{ projectId?: string; limit?: number }>();
 97→  const db = getDb();
 98→
 99→  const conditions: string[] = [];
100→  const params: (string | number)[] = [];
101→
102→  if (body.projectId) {
103→    conditions.push('project_id = ?');
104→    params.push(body.projectId);
105→  }
106→
107→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
108→  const limit = Math.min(parseIntParam(String(body.limit ?? ''), 200), 200);
109→
110→  const insights = db.prepare(`
111→    SELECT id, type, title, summary, project_name, session_id
112→    FROM insights
113→    ${where}
114→    ORDER BY timestamp DESC
115→    LIMIT ?
116→  `).all(...params, limit) as Array<{
117→    id: string;
118→    type: string;
119→    title: string;
120→    summary: string;
121→    project_name: string;
122→    session_id: string;
123→  }>;
124→
125→  const result = await findRecurringInsights(insights);
126→  if (result.success) trackEvent('analysis', true, 'recurring');
127→  return c.json(result, result.success ? 200 : 422);
128→});
129→
130→export default app;
