  1→// Core analysis engine — server-side.
  2→// Ported from web repo (src/lib/llm/analysis.ts) with SQLite persistence replacing Firestore.
  3→// Key differences from web repo:
  4→//   - Uses SQLiteMessageRow instead of web Message type
  5→//   - Writes insights directly to SQLite via getDb() (not Firestore)
  6→//   - Abort handling uses error.name === 'AbortError' (not DOMException)
  7→//   - Uses session's existing project_id from SQLite (not re-derived hash)
  8→
  9→import { randomUUID } from 'crypto';
 10→import { getDb } from '@code-insights/cli/db/client';
 11→import { createLLMClient, isLLMConfigured } from './client.js';
 12→import {
 13→  SESSION_ANALYSIS_SYSTEM_PROMPT,
 14→  generateSessionAnalysisPrompt,
 15→  formatMessagesForAnalysis,
 16→  parseAnalysisResponse,
 17→  PROMPT_QUALITY_SYSTEM_PROMPT,
 18→  generatePromptQualityPrompt,
 19→  parsePromptQualityResponse,
 20→  type SQLiteMessageRow,
 21→  type AnalysisResponse,
 22→  type PromptQualityResponse,
 23→} from './prompts.js';
 24→
 25→// Re-export SQLiteMessageRow so routes can import it from analysis.ts directly
 26→export type { SQLiteMessageRow };
 27→
 28→// Maximum tokens to send to LLM (leaving room for response)
 29→const MAX_INPUT_TOKENS = 80000;
 30→const ANALYSIS_VERSION = '2.0.0';
 31→
 32→export interface AnalysisProgress {
 33→  phase: 'loading_messages' | 'analyzing' | 'saving';
 34→  currentChunk?: number;
 35→  totalChunks?: number;
 36→}
 37→
 38→export interface AnalysisOptions {
 39→  onProgress?: (progress: AnalysisProgress) => void;
 40→  signal?: AbortSignal;
 41→}
 42→
 43→export interface AnalysisResult {
 44→  success: boolean;
 45→  insights: InsightRow[];
 46→  error?: string;
 47→  usage?: {
 48→    inputTokens: number;
 49→    outputTokens: number;
 50→  };
 51→}
 52→
 53→// Shape of a saved insight row (matches the SQLite schema)
 54→export interface InsightRow {
 55→  id: string;
 56→  session_id: string;
 57→  project_id: string;
 58→  project_name: string;
 59→  type: string;
 60→  title: string;
 61→  content: string;
 62→  summary: string;
 63→  bullets: string;           // JSON-encoded string[]
 64→  confidence: number;
 65→  source: 'llm';
 66→  metadata: string | null;   // JSON-encoded object
 67→  timestamp: string;         // ISO 8601
 68→  created_at: string;        // ISO 8601
 69→  scope: string;
 70→  analysis_version: string;
 71→}
 72→
 73→// Minimal session data needed for analysis (from SQLite sessions row)
 74→export interface SessionData {
 75→  id: string;
 76→  project_id: string;
 77→  project_name: string;
 78→  project_path: string;
 79→  summary: string | null;
 80→  ended_at: string;          // ISO 8601
 81→}
 82→
 83→/**
 84→ * Analyze a session and generate insights, saving them to SQLite.
 85→ */
 86→export async function analyzeSession(
 87→  session: SessionData,
 88→  messages: SQLiteMessageRow[],
 89→  options?: AnalysisOptions
 90→): Promise<AnalysisResult> {
 91→  if (!isLLMConfigured()) {
 92→    return {
 93→      success: false,
 94→      insights: [],
 95→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 96→    };
 97→  }
 98→
 99→  if (messages.length === 0) {
100→    return {
101→      success: false,
102→      insights: [],
103→      error: 'No messages found for this session.',
104→    };
105→  }
106→
107→  try {
108→    const client = createLLMClient();
109→    const formattedMessages = formatMessagesForAnalysis(messages);
110→    const estimatedTokens = client.estimateTokens(formattedMessages);
111→
112→    let analysisResponse: AnalysisResponse;
113→    let totalInputTokens = 0;
114→    let totalOutputTokens = 0;
115→
116→    if (estimatedTokens > MAX_INPUT_TOKENS) {
117→      // Chunk the messages and analyze separately
118→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
119→      const chunkResponses: AnalysisResponse[] = [];
120→      const totalChunks = chunks.length;
121→
122→      for (let i = 0; i < chunks.length; i++) {
123→        const chunk = chunks[i];
124→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
125→
126→        const chunkFormatted = formatMessagesForAnalysis(chunk);
127→        const prompt = generateSessionAnalysisPrompt(
128→          session.project_name,
129→          session.summary,
130→          chunkFormatted
131→        );
132→
133→        const response = await client.chat([
134→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
135→          { role: 'user', content: prompt },
136→        ], { signal: options?.signal });
137→
138→        if (response.usage) {
139→          totalInputTokens += response.usage.inputTokens;
140→          totalOutputTokens += response.usage.outputTokens;
141→        }
142→
143→        const parsed = parseAnalysisResponse(response.content);
144→        if (parsed) chunkResponses.push(parsed);
145→      }
146→
147→      analysisResponse = mergeAnalysisResponses(chunkResponses);
148→    } else {
149→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
150→      const prompt = generateSessionAnalysisPrompt(
151→        session.project_name,
152→        session.summary,
153→        formattedMessages
154→      );
155→
156→      const response = await client.chat([
157→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
158→        { role: 'user', content: prompt },
159→      ], { signal: options?.signal });
160→
161→      if (response.usage) {
162→        totalInputTokens = response.usage.inputTokens;
163→        totalOutputTokens = response.usage.outputTokens;
164→      }
165→
166→      const parsed = parseAnalysisResponse(response.content);
167→      if (!parsed) {
168→        return {
169→          success: false,
170→          insights: [],
171→          error: 'Failed to parse LLM response. Please try again.',
172→        };
173→      }
174→
175→      analysisResponse = parsed;
176→    }
177→
178→    options?.onProgress?.({ phase: 'saving' });
179→    const insights = convertToInsightRows(analysisResponse, session);
180→
181→    // Save new insights first, then delete old non-prompt-quality insights
182→    // (safe order: if save fails, old data is preserved)
183→    saveInsightsToDb(insights);
184→    deleteSessionInsights(session.id, {
185→      excludeTypes: ['prompt_quality'],
186→      excludeIds: insights.map(i => i.id),
187→    });
188→
189→    return {
190→      success: true,
191→      insights,
192→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
193→    };
194→  } catch (error) {
195→    if (error instanceof Error && error.name === 'AbortError') {
196→      return { success: false, insights: [], error: 'Analysis cancelled' };
197→    }
198→    return {
199→      success: false,
200→      insights: [],
201→      error: error instanceof Error ? error.message : 'Analysis failed',
202→    };
203→  }
204→}
205→
206→/**
207→ * Analyze prompt quality for a session.
208→ */
209→export async function analyzePromptQuality(
210→  session: SessionData,
211→  messages: SQLiteMessageRow[],
212→  options?: AnalysisOptions
213→): Promise<AnalysisResult> {
214→  if (!isLLMConfigured()) {
215→    return {
216→      success: false,
217→      insights: [],
218→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
219→    };
220→  }
221→
222→  if (messages.length === 0) {
223→    return {
224→      success: false,
225→      insights: [],
226→      error: 'No messages found for this session.',
227→    };
228→  }
229→
230→  const userMessages = messages.filter(m => m.type === 'user');
231→  if (userMessages.length < 2) {
232→    return {
233→      success: false,
234→      insights: [],
235→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
236→    };
237→  }
238→
239→  try {
240→    const client = createLLMClient();
241→    const formattedMessages = formatMessagesForAnalysis(messages);
242→
243→    let analysisInput = formattedMessages;
244→    const estimatedTokens = client.estimateTokens(formattedMessages);
245→    if (estimatedTokens > MAX_INPUT_TOKENS) {
246→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
247→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
248→    }
249→
250→    const prompt = generatePromptQualityPrompt(
251→      session.project_name,
252→      analysisInput,
253→      messages.length
254→    );
255→
256→    options?.onProgress?.({ phase: 'analyzing' });
257→    const response = await client.chat([
258→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
259→      { role: 'user', content: prompt },
260→    ], { signal: options?.signal });
261→
262→    const parsed = parsePromptQualityResponse(response.content);
263→    if (!parsed) {
264→      return {
265→        success: false,
266→        insights: [],
267→        error: 'Failed to parse prompt quality analysis. Please try again.',
268→      };
269→    }
270→
271→    options?.onProgress?.({ phase: 'saving' });
272→    const insight = convertPromptQualityToInsightRow(parsed, session);
273→
274→    // Save new insight, then delete old prompt_quality insights
275→    saveInsightsToDb([insight]);
276→    deleteSessionInsights(session.id, {
277→      includeOnlyTypes: ['prompt_quality'],
278→      excludeIds: [insight.id],
279→    });
280→
281→    return {
282→      success: true,
283→      insights: [insight],
284→      usage: response.usage ? {
285→        inputTokens: response.usage.inputTokens,
286→        outputTokens: response.usage.outputTokens,
287→      } : undefined,
288→    };
289→  } catch (error) {
290→    if (error instanceof Error && error.name === 'AbortError') {
291→      return { success: false, insights: [], error: 'Analysis cancelled' };
292→    }
293→    return {
294→      success: false,
295→      insights: [],
296→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
297→    };
298→  }
299→}
300→
301→export interface RecurringInsightGroup {
302→  insightIds: string[];
303→  theme: string;
304→}
305→
306→export interface RecurringInsightResult {
307→  success: boolean;
308→  groups: RecurringInsightGroup[];
309→  updatedCount: number;
310→  error?: string;
311→  usage?: {
312→    inputTokens: number;
313→    outputTokens: number;
314→  };
315→}
316→
317→/**
318→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
319→ */
320→export async function findRecurringInsights(
321→  insights: Array<{
322→    id: string;
323→    type: string;
324→    title: string;
325→    summary: string;
326→    project_name: string;
327→    session_id: string;
328→  }>
329→): Promise<RecurringInsightResult> {
330→  if (!isLLMConfigured()) {
331→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
332→  }
333→
334→  const candidates = insights
335→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
336→    .slice(0, 200);
337→
338→  if (candidates.length < 2) {
339→    return {
340→      success: false,
341→      groups: [],
342→      updatedCount: 0,
343→      error: 'Need at least 2 non-summary insights to find patterns.',
344→    };
345→  }
346→
347→  try {
348→    const client = createLLMClient();
349→
350→    const insightData = candidates.map(i => ({
351→      id: i.id,
352→      type: i.type === 'technique' ? 'learning' : i.type,
353→      title: i.title,
354→      summary: i.summary.slice(0, 150),
355→      projectName: i.project_name,
356→      sessionId: i.session_id,
357→    }));
358→
359→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
360→
361→RULES:
362→- Only group insights that are genuinely about the same concept/topic
363→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
364→- A group must have at least 2 insights
365→- An insight can only belong to one group
366→- Provide a brief "theme" describing what the group shares
367→- If no recurring patterns exist, return an empty groups array
368→
369→INSIGHTS:
370→${JSON.stringify(insightData, null, 2)}
371→
372→Respond with valid JSON only:
373→{
374→  "groups": [
375→    {
376→      "insightIds": ["insight_abc", "insight_def"],
377→      "theme": "Brief description of the shared concept"
378→    }
379→  ]
380→}`;
381→
382→    const response = await client.chat([
383→      {
384→        role: 'system',
385→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
386→      },
387→      { role: 'user', content: prompt },
388→    ]);
389→
390→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
391→    if (!jsonMatch) {
392→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
393→    }
394→
395→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
396→    const groups = parsed.groups || [];
397→
398→    const validIds = new Set(candidates.map(i => i.id));
399→    const validGroups = groups
400→      .map(g => ({
401→        ...g,
402→        insightIds: g.insightIds.filter(id => validIds.has(id)),
403→      }))
404→      .filter(g => g.insightIds.length >= 2);
405→
406→    if (validGroups.length === 0) {
407→      return {
408→        success: true,
409→        groups: [],
410→        updatedCount: 0,
411→        usage: response.usage
412→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
413→          : undefined,
414→      };
415→    }
416→
417→    // Build bidirectional links
418→    const linkMap = new Map<string, string[]>();
419→    for (const group of validGroups) {
420→      for (const id of group.insightIds) {
421→        const others = group.insightIds.filter(otherId => otherId !== id);
422→        const existing = linkMap.get(id) || [];
423→        linkMap.set(id, [...new Set([...existing, ...others])]);
424→      }
425→    }
426→
427→    // Write links to SQLite
428→    const db = getDb();
429→    const updateLinks = db.prepare(
430→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
431→    );
432→
433→    for (const [insightId, linkedIds] of linkMap.entries()) {
434→      updateLinks.run(JSON.stringify(linkedIds), insightId);
435→    }
436→
437→    return {
438→      success: true,
439→      groups: validGroups,
440→      updatedCount: linkMap.size,
441→      usage: response.usage
442→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
443→        : undefined,
444→    };
445→  } catch (error) {
446→    return {
447→      success: false,
448→      groups: [],
449→      updatedCount: 0,
450→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
451→    };
452→  }
453→}
454→
455→// --- Internal helpers ---
456→
457→function chunkMessages(
458→  messages: SQLiteMessageRow[],
459→  estimateTokens: (text: string) => number
460→): SQLiteMessageRow[][] {
461→  const chunks: SQLiteMessageRow[][] = [];
462→  let currentChunk: SQLiteMessageRow[] = [];
463→  let currentTokens = 0;
464→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
465→
466→  for (const message of messages) {
467→    let toolResults: Array<{ output?: string }> = [];
468→    try {
469→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
470→    } catch {
471→      toolResults = [];
472→    }
473→
474→    const messageText = [
475→      message.content,
476→      message.thinking?.slice(0, 1000) ?? '',
477→      ...toolResults.map(r => (r.output || '').slice(0, 200)),
478→    ].join(' ');
479→    const messageTokens = estimateTokens(messageText);
480→
481→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
482→      chunks.push(currentChunk);
483→      currentChunk = [];
484→      currentTokens = 0;
485→    }
486→
487→    currentChunk.push(message);
488→    currentTokens += messageTokens;
489→  }
490→
491→  if (currentChunk.length > 0) {
492→    chunks.push(currentChunk);
493→  }
494→
495→  return chunks;
496→}
497→
498→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
499→  if (responses.length === 0) {
500→    return {
501→      summary: { title: 'Analysis failed', content: '', bullets: [] },
502→      decisions: [],
503→      learnings: [],
504→    };
505→  }
506→
507→  if (responses.length === 1) return responses[0];
508→
509→  const merged: AnalysisResponse = {
510→    summary: responses[0].summary,
511→    decisions: [],
512→    learnings: [],
513→  };
514→
515→  for (const response of responses) {
516→    merged.decisions.push(...response.decisions);
517→    merged.learnings.push(...response.learnings);
518→  }
519→
520→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
521→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
522→
523→  return merged;
524→}
525→
526→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
527→  const seen = new Set<string>();
528→  return items.filter((item) => {
529→    const normalized = item.title.toLowerCase().trim();
530→    if (seen.has(normalized)) return false;
531→    seen.add(normalized);
532→    return true;
533→  });
534→}
535→
536→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
537→  const insights: InsightRow[] = [];
538→  const now = new Date().toISOString();
539→
540→  insights.push({
541→    id: randomUUID(),
542→    session_id: session.id,
543→    project_id: session.project_id,
544→    project_name: session.project_name,
545→    type: 'summary',
546→    title: response.summary.title,
547→    content: response.summary.content,
548→    summary: response.summary.content,
549→    bullets: JSON.stringify(response.summary.bullets),
550→    confidence: 0.9,
551→    source: 'llm',
552→    metadata: null,
553→    timestamp: session.ended_at,
554→    created_at: now,
555→    scope: 'session',
556→    analysis_version: ANALYSIS_VERSION,
557→  });
558→
559→  for (const decision of response.decisions) {
560→    const confidence = decision.confidence ?? 85;
561→    if (confidence < 70) continue;
562→
563→    insights.push({
564→      id: randomUUID(),
565→      session_id: session.id,
566→      project_id: session.project_id,
567→      project_name: session.project_name,
568→      type: 'decision',
569→      title: decision.title,
570→      content: decision.content,
571→      summary: decision.content.slice(0, 200),
572→      bullets: JSON.stringify(decision.alternatives || []),
573→      confidence: confidence / 100,
574→      source: 'llm',
575→      metadata: JSON.stringify({
576→        reasoning: decision.reasoning,
577→        alternatives: decision.alternatives,
578→        evidence: decision.evidence,
579→      }),
580→      timestamp: session.ended_at,
581→      created_at: now,
582→      scope: 'session',
583→      analysis_version: ANALYSIS_VERSION,
584→    });
585→  }
586→
587→  for (const learning of response.learnings) {
588→    const confidence = learning.confidence ?? 80;
589→    if (confidence < 70) continue;
590→
591→    insights.push({
592→      id: randomUUID(),
593→      session_id: session.id,
594→      project_id: session.project_id,
595→      project_name: session.project_name,
596→      type: 'learning',
597→      title: learning.title,
598→      content: learning.content,
599→      summary: learning.content.slice(0, 200),
600→      bullets: JSON.stringify([]),
601→      confidence: confidence / 100,
602→      source: 'llm',
603→      metadata: JSON.stringify({
604→        context: learning.context,
605→        evidence: learning.evidence,
606→      }),
607→      timestamp: session.ended_at,
608→      created_at: now,
609→      scope: 'session',
610→      analysis_version: ANALYSIS_VERSION,
611→    });
612→  }
613→
614→  return insights;
615→}
616→
617→function convertPromptQualityToInsightRow(response: PromptQualityResponse, session: SessionData): InsightRow {
618→  const now = new Date().toISOString();
619→
620→  return {
621→    id: randomUUID(),
622→    session_id: session.id,
623→    project_id: session.project_id,
624→    project_name: session.project_name,
625→    type: 'prompt_quality',
626→    title: `Prompt Efficiency: ${response.efficiencyScore}/100`,
627→    content: response.overallAssessment,
628→    summary: response.overallAssessment,
629→    bullets: JSON.stringify(response.tips),
630→    confidence: 0.85,
631→    source: 'llm',
632→    metadata: JSON.stringify({
633→      efficiencyScore: response.efficiencyScore,
634→      wastedTurns: response.wastedTurns,
635→      antiPatterns: response.antiPatterns,
636→      potentialMessageReduction: response.potentialMessageReduction,
637→    }),
638→    timestamp: session.ended_at,
639→    created_at: now,
640→    scope: 'session',
641→    analysis_version: ANALYSIS_VERSION,
642→  };
643→}
644→
645→/**
646→ * Write insight rows to SQLite using prepared statements.
647→ */
648→function saveInsightsToDb(insights: InsightRow[]): void {
649→  const db = getDb();
650→  const insert = db.prepare(`
651→    INSERT OR REPLACE INTO insights (
652→      id, session_id, project_id, project_name, type, title, content,
653→      summary, bullets, confidence, source, metadata, timestamp,
654→      created_at, scope, analysis_version
655→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
656→  `);
657→
658→  const insertMany = db.transaction((rows: InsightRow[]) => {
659→    for (const row of rows) {
660→      insert.run(
661→        row.id,
662→        row.session_id,
663→        row.project_id,
664→        row.project_name,
665→        row.type,
666→        row.title,
667→        row.content,
668→        row.summary,
669→        row.bullets,
670→        row.confidence,
671→        row.source,
672→        row.metadata,
673→        row.timestamp,
674→        row.created_at,
675→        row.scope,
676→        row.analysis_version,
677→      );
678→    }
679→  });
680→
681→  insertMany(insights);
682→}
683→
684→interface DeleteOptions {
685→  excludeTypes?: string[];
686→  includeOnlyTypes?: string[];
687→  excludeIds?: string[];
688→}
689→
690→/**
691→ * Delete insights for a session, with optional type and ID exclusions.
692→ */
693→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
694→  const db = getDb();
695→  const conditions: string[] = ['session_id = ?'];
696→  const params: (string | number)[] = [sessionId];
697→
698→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
699→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
700→    params.push(...opts.excludeTypes);
701→  }
702→
703→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
704→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
705→    params.push(...opts.includeOnlyTypes);
706→  }
707→
708→  if (opts.excludeIds && opts.excludeIds.length > 0) {
709→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
710→    params.push(...opts.excludeIds);
711→  }
712→
713→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
714→}
