 83→/**
 84→ * Analyze a session and generate insights, saving them to SQLite.
 85→ */
 86→export async function analyzeSession(
 87→  session: SessionData,
 88→  messages: SQLiteMessageRow[],
 89→  options?: AnalysisOptions
 90→): Promise<AnalysisResult> {
 91→  if (!isLLMConfigured()) {
 92→    return {
 93→      success: false,
 94→      insights: [],
 95→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 96→    };
 97→  }
 98→
 99→  if (messages.length === 0) {
100→    return {
101→      success: false,
102→      insights: [],
103→      error: 'No messages found for this session.',
104→    };
105→  }
106→
107→  try {
108→    const client = createLLMClient();
109→    const formattedMessages = formatMessagesForAnalysis(messages);
110→    const estimatedTokens = client.estimateTokens(formattedMessages);
111→
112→    let analysisResponse: AnalysisResponse;
113→    let totalInputTokens = 0;
114→    let totalOutputTokens = 0;
115→
116→    if (estimatedTokens > MAX_INPUT_TOKENS) {
117→      // Chunk the messages and analyze separately
118→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
119→      const chunkResponses: AnalysisResponse[] = [];
120→      const totalChunks = chunks.length;
121→
122→      for (let i = 0; i < chunks.length; i++) {
123→        const chunk = chunks[i];
124→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
125→
126→        const chunkFormatted = formatMessagesForAnalysis(chunk);
127→        const prompt = generateSessionAnalysisPrompt(
128→          session.project_name,
129→          session.summary,
130→          chunkFormatted
131→        );
132→
133→        const response = await client.chat([
134→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
135→          { role: 'user', content: prompt },
136→        ], { signal: options?.signal });
137→
138→        if (response.usage) {
139→          totalInputTokens += response.usage.inputTokens;
140→          totalOutputTokens += response.usage.outputTokens;
141→        }
142→
143→        const parsed = parseAnalysisResponse(response.content);
144→        if (parsed) chunkResponses.push(parsed);
145→      }
146→
147→      analysisResponse = mergeAnalysisResponses(chunkResponses);
148→    } else {
149→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
150→      const prompt = generateSessionAnalysisPrompt(
151→        session.project_name,
152→        session.summary,
153→        formattedMessages
154→      );
155→
156→      const response = await client.chat([
157→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
158→        { role: 'user', content: prompt },
159→      ], { signal: options?.signal });
160→
161→      if (response.usage) {
162→        totalInputTokens = response.usage.inputTokens;
163→        totalOutputTokens = response.usage.outputTokens;
164→      }
165→
166→      const parsed = parseAnalysisResponse(response.content);
167→      if (!parsed) {
168→        return {
169→          success: false,
170→          insights: [],
171→          error: 'Failed to parse LLM response. Please try again.',
172→        };
173→      }
174→
175→      analysisResponse = parsed;
176→    }
177→
178→    options?.onProgress?.({ phase: 'saving' });
179→    const insights = convertToInsightRows(analysisResponse, session);
180→
181→    // Save new insights first, then delete old non-prompt-quality insights
182→    // (safe order: if save fails, old data is preserved)
183→    saveInsightsToDb(insights);
184→    deleteSessionInsights(session.id, {
185→      excludeTypes: ['prompt_quality'],
186→      excludeIds: insights.map(i => i.id),
187→    });
188→
189→    return {
190→      success: true,
191→      insights,
192→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
193→    };
194→  } catch (error) {
195→    if (error instanceof Error && error.name === 'AbortError') {
196→      return { success: false, insights: [], error: 'Analysis cancelled' };
197→    }
198→    return {
199→      success: false,
200→      insights: [],
201→      error: error instanceof Error ? error.message : 'Analysis failed',
202→    };
203→  }
204→}
