206→/**
207→ * Analyze prompt quality for a session.
208→ */
209→export async function analyzePromptQuality(
210→  session: SessionData,
211→  messages: SQLiteMessageRow[],
212→  options?: AnalysisOptions
213→): Promise<AnalysisResult> {
214→  if (!isLLMConfigured()) {
215→    return {
216→      success: false,
217→      insights: [],
218→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
219→    };
220→  }
221→
222→  if (messages.length === 0) {
223→    return {
224→      success: false,
225→      insights: [],
226→      error: 'No messages found for this session.',
227→    };
228→  }
229→
230→  const userMessages = messages.filter(m => m.type === 'user');
231→  if (userMessages.length < 2) {
232→    return {
233→      success: false,
234→      insights: [],
235→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
236→    };
237→  }
238→
239→  try {
240→    const client = createLLMClient();
241→    const formattedMessages = formatMessagesForAnalysis(messages);
242→
243→    let analysisInput = formattedMessages;
244→    const estimatedTokens = client.estimateTokens(formattedMessages);
245→    if (estimatedTokens > MAX_INPUT_TOKENS) {
246→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
247→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
248→    }
249→
250→    const prompt = generatePromptQualityPrompt(
251→      session.project_name,
252→      analysisInput,
253→      messages.length
254→    );
255→
256→    options?.onProgress?.({ phase: 'analyzing' });
257→    const response = await client.chat([
258→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
259→      { role: 'user', content: prompt },
260→    ], { signal: options?.signal });
261→
262→    const parsed = parsePromptQualityResponse(response.content);
263→    if (!parsed) {
264→      return {
265→        success: false,
266→        insights: [],
267→        error: 'Failed to parse prompt quality analysis. Please try again.',
268→      };
269→    }
270→
271→    options?.onProgress?.({ phase: 'saving' });
272→    const insight = convertPromptQualityToInsightRow(parsed, session);
273→
274→    // Save new insight, then delete old prompt_quality insights
275→    saveInsightsToDb([insight]);
276→    deleteSessionInsights(session.id, {
277→      includeOnlyTypes: ['prompt_quality'],
278→      excludeIds: [insight.id],
279→    });
280→
281→    return {
282→      success: true,
283→      insights: [insight],
284→      usage: response.usage ? {
285→        inputTokens: response.usage.inputTokens,
286→        outputTokens: response.usage.outputTokens,
287→      } : undefined,
288→    };
289→  } catch (error) {
290→    if (error instanceof Error && error.name === 'AbortError') {
291→      return { success: false, insights: [], error: 'Analysis cancelled' };
292→    }
293→    return {
294→      success: false,
295→      insights: [],
296→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
297→    };
298→  }
299→}
