536→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
537→  const insights: InsightRow[] = [];
538→  const now = new Date().toISOString();
539→
540→  insights.push({
541→    id: randomUUID(),
542→    session_id: session.id,
543→    project_id: session.project_id,
544→    project_name: session.project_name,
545→    type: 'summary',
546→    title: response.summary.title,
547→    content: response.summary.content,
548→    summary: response.summary.content,
549→    bullets: JSON.stringify(response.summary.bullets),
550→    confidence: 0.9,
551→    source: 'llm',
552→    metadata: null,
553→    timestamp: session.ended_at,
554→    created_at: now,
555→    scope: 'session',
556→    analysis_version: ANALYSIS_VERSION,
557→  });
558→
559→  for (const decision of response.decisions) {
560→    const confidence = decision.confidence ?? 85;
561→    if (confidence < 70) continue;
562→
563→    insights.push({
564→      id: randomUUID(),
565→      session_id: session.id,
566→      project_id: session.project_id,
567→      project_name: session.project_name,
568→      type: 'decision',
569→      title: decision.title,
570→      content: decision.content,
571→      summary: decision.content.slice(0, 200),
572→      bullets: JSON.stringify(decision.alternatives || []),
573→      confidence: confidence / 100,
574→      source: 'llm',
575→      metadata: JSON.stringify({
576→        reasoning: decision.reasoning,
577→        alternatives: decision.alternatives,
578→        evidence: decision.evidence,
579→      }),
580→      timestamp: session.ended_at,
581→      created_at: now,
582→      scope: 'session',
583→      analysis_version: ANALYSIS_VERSION,
584→    });
585→  }
586→
587→  for (const learning of response.learnings) {
588→    const confidence = learning.confidence ?? 80;
589→    if (confidence < 70) continue;
590→
591→    insights.push({
592→      id: randomUUID(),
593→      session_id: session.id,
594→      project_id: session.project_id,
595→      project_name: session.project_name,
596→      type: 'learning',
597→      title: learning.title,
598→      content: learning.content,
599→      summary: learning.content.slice(0, 200),
600→      bullets: JSON.stringify([]),
601→      confidence: confidence / 100,
602→      source: 'llm',
603→      metadata: JSON.stringify({
604→        context: learning.context,
605→        evidence: learning.evidence,
606→      }),
607→      timestamp: session.ended_at,
608→      created_at: now,
609→      scope: 'session',
610→      analysis_version: ANALYSIS_VERSION,
611→    });
612→  }
613→
614→  return insights;
615→}
