  1→/**
  2→ * Analysis context for the embedded dashboard.
  3→ * Unlike the web app which calls LLM providers directly in the browser,
  4→ * this version delegates all analysis to the Hono server via POST /api/analysis/session.
  5→ * The useAnalyzeSession() hook from Layer 2 handles the API call.
  6→ */
  7→import {
  8→  createContext,
  9→  useContext,
 10→  useState,
 11→  useCallback,
 12→  ReactNode,
 13→} from 'react';
 14→import { useQueryClient } from '@tanstack/react-query';
 15→import { analyzeSession, analyzePromptQuality } from '@/lib/api';
 16→import { getSessionTitle } from '@/lib/utils';
 17→import type { Session } from '@/lib/types';
 18→import { toast } from 'sonner';
 19→
 20→const ANALYSIS_TOAST_ID = 'analysis-toast';
 21→
 22→export interface AnalysisState {
 23→  status: 'idle' | 'analyzing' | 'complete' | 'error';
 24→  sessionId: string | null;
 25→  sessionTitle: string | null;
 26→  type: 'session' | 'prompt_quality';
 27→  progress: { message: string } | null;
 28→  result: {
 29→    success: boolean;
 30→    insightCount?: number;
 31→    error?: string;
 32→  } | null;
 33→}
 34→
 35→interface AnalysisContextValue {
 36→  state: AnalysisState;
 37→  startAnalysis: (session: Session, type: 'session' | 'prompt_quality') => Promise<void>;
 38→  cancelAnalysis: () => void;
 39→  clearResult: () => void;
 40→}
 41→
 42→const IDLE_STATE: AnalysisState = {
 43→  status: 'idle',
 44→  sessionId: null,
 45→  sessionTitle: null,
 46→  type: 'session',
 47→  progress: null,
 48→  result: null,
 49→};
 50→
 51→const AnalysisContext = createContext<AnalysisContextValue>({
 52→  state: IDLE_STATE,
 53→  startAnalysis: async () => {},
 54→  cancelAnalysis: () => {},
 55→  clearResult: () => {},
 56→});
 57→
 58→export function useAnalysis() {
 59→  return useContext(AnalysisContext);
 60→}
 61→
 62→export function AnalysisProvider({ children }: { children: ReactNode }) {
 63→  const [state, setState] = useState<AnalysisState>(IDLE_STATE);
 64→  const queryClient = useQueryClient();
 65→
 66→  const cancelAnalysis = useCallback(() => {
 67→    setState(IDLE_STATE);
 68→    toast.dismiss(ANALYSIS_TOAST_ID);
 69→  }, []);
 70→
 71→  const clearResult = useCallback(() => {
 72→    setState(IDLE_STATE);
 73→  }, []);
 74→
 75→  const startAnalysis = useCallback(
 76→    async (session: Session, type: 'session' | 'prompt_quality') => {
 77→      if (state.status === 'analyzing') {
 78→        toast.warning('Analysis already in progress.');
 79→        return;
 80→      }
 81→
 82→      const sessionTitle = getSessionTitle(session);
 83→
 84→      setState({
 85→        status: 'analyzing',
 86→        sessionId: session.id,
 87→        sessionTitle,
 88→        type,
 89→        progress: { message: `Analyzing "${sessionTitle}"...` },
 90→        result: null,
 91→      });
 92→
 93→      toast.loading(`Analyzing "${sessionTitle}"...`, { id: ANALYSIS_TOAST_ID });
 94→
 95→      try {
 96→        if (type === 'session') {
 97→          await analyzeSession(session.id);
 98→        } else {
 99→          await analyzePromptQuality(session.id);
100→        }
101→
102→        // Invalidate queries so data refreshes
103→        queryClient.invalidateQueries({ queryKey: ['insights'] });
104→        queryClient.invalidateQueries({ queryKey: ['session', session.id] });
105→
106→        setState({
107→          status: 'complete',
108→          sessionId: session.id,
109→          sessionTitle,
110→          type,
111→          progress: null,
112→          result: { success: true },
113→        });
114→        toast.success('Analysis complete!', { id: ANALYSIS_TOAST_ID });
115→      } catch (error) {
116→        const errorMsg = error instanceof Error ? error.message : 'Analysis failed';
117→        setState({
118→          status: 'error',
119→          sessionId: session.id,
120→          sessionTitle,
121→          type,
122→          progress: null,
123→          result: { success: false, error: errorMsg },
124→        });
125→        toast.error(`Analysis failed: ${errorMsg}`, { id: ANALYSIS_TOAST_ID });
126→      }
127→    },
128→    [state.status, queryClient]
129→  );
130→
131→  return (
132→    <AnalysisContext.Provider value={{ state, startAnalysis, cancelAnalysis, clearResult }}>
133→      {children}
134→    </AnalysisContext.Provider>
135→  );
136→}
137→

