  1→import { useState } from 'react';
  2→import { Sparkles, Loader2, CheckCircle, AlertCircle } from 'lucide-react';
  3→import { Button } from '@/components/ui/button';
  4→import {
  5→  Dialog,
  6→  DialogContent,
  7→  DialogDescription,
  8→  DialogHeader,
  9→  DialogTitle,
 10→  DialogTrigger,
 11→} from '@/components/ui/dialog';
 12→import { analyzeSession } from '@/lib/api';
 13→import { useLlmConfig } from '@/hooks/useConfig';
 14→import { useQueryClient } from '@tanstack/react-query';
 15→import type { Session } from '@/lib/types';
 16→
 17→interface BulkAnalyzeButtonProps {
 18→  sessions: Session[];
 19→  onComplete?: () => void;
 20→}
 21→
 22→export function BulkAnalyzeButton({ sessions, onComplete }: BulkAnalyzeButtonProps) {
 23→  const [open, setOpen] = useState(false);
 24→  const [analyzing, setAnalyzing] = useState(false);
 25→  const [progress, setProgress] = useState({ completed: 0, total: 0 });
 26→  const [result, setResult] = useState<{
 27→    successful: number;
 28→    failed: number;
 29→    errors: string[];
 30→  } | null>(null);
 31→  const { data: llmConfig } = useLlmConfig();
 32→  const queryClient = useQueryClient();
 33→
 34→  const configured = !!(llmConfig?.provider && llmConfig?.model);
 35→
 36→  const handleAnalyze = async () => {
 37→    if (!configured || sessions.length === 0) return;
 38→
 39→    setAnalyzing(true);
 40→    setProgress({ completed: 0, total: sessions.length });
 41→    setResult(null);
 42→
 43→    let successful = 0;
 44→    let failed = 0;
 45→    const errors: string[] = [];
 46→
 47→    for (const session of sessions) {
 48→      try {
 49→        await analyzeSession(session.id);
 50→        successful++;
 51→      } catch (error) {
 52→        failed++;
 53→        errors.push(error instanceof Error ? error.message : `Failed: ${session.id}`);
 54→      }
 55→      setProgress((prev) => ({ ...prev, completed: prev.completed + 1 }));
 56→    }
 57→
 58→    // Invalidate all insight queries
 59→    queryClient.invalidateQueries({ queryKey: ['insights'] });
 60→    queryClient.invalidateQueries({ queryKey: ['sessions'] });
 61→
 62→    setResult({ successful, failed, errors });
 63→    setAnalyzing(false);
 64→    onComplete?.();
 65→  };
 66→
 67→  const handleClose = () => {
 68→    if (!analyzing) {
 69→      setOpen(false);
 70→      setResult(null);
 71→      setProgress({ completed: 0, total: 0 });
 72→    }
 73→  };
 74→
 75→  if (!configured) {
 76→    return (
 77→      <Button variant="outline" disabled className="gap-2">
 78→        <Sparkles className="h-4 w-4" />
 79→        Analyze Selected
 80→        <span className="text-xs text-muted-foreground ml-1">(Configure AI first)</span>
 81→      </Button>
 82→    );
 83→  }
 84→
 85→  return (
 86→    <Dialog open={open} onOpenChange={handleClose}>
 87→      <DialogTrigger asChild>
 88→        <Button
 89→          variant="outline"
 90→          className="gap-2"
 91→          disabled={sessions.length === 0}
 92→          onClick={() => setOpen(true)}
 93→        >
 94→          <Sparkles className="h-4 w-4" />
 95→          Analyze {sessions.length} Session{sessions.length !== 1 ? 's' : ''}
 96→        </Button>
 97→      </DialogTrigger>
 98→      <DialogContent>
 99→        <DialogHeader>
100→          <DialogTitle>Bulk Analysis</DialogTitle>
101→          <DialogDescription>
102→            Generate AI insights for {sessions.length} selected session
103→            {sessions.length !== 1 ? 's' : ''}.
104→          </DialogDescription>
105→        </DialogHeader>
106→
107→        <div className="space-y-4 py-4">
108→          {!analyzing && !result && (
109→            <>
110→              <p className="text-sm text-muted-foreground">
111→                This will use your configured LLM provider to analyze each session and generate insights.
112→              </p>
113→              <Button onClick={handleAnalyze} className="w-full gap-2">
114→                <Sparkles className="h-4 w-4" />
115→                Start Analysis
116→              </Button>
117→            </>
118→          )}
119→
120→          {analyzing && (
121→            <div className="space-y-3">
122→              <div className="flex items-center gap-2">
123→                <Loader2 className="h-4 w-4 animate-spin" />
124→                <span className="text-sm">
125→                  Analyzing session {progress.completed} of {progress.total}...
126→                </span>
127→              </div>
128→              <div className="w-full bg-muted rounded-full h-2">
129→                <div
130→                  className="bg-primary h-2 rounded-full transition-all"
131→                  style={{ width: `${progress.total > 0 ? (progress.completed / progress.total) * 100 : 0}%` }}
132→                />
133→              </div>
134→            </div>
135→          )}
136→
137→          {result && (
138→            <div className="space-y-3">
139→              <div className="flex items-center gap-2 text-green-600">
140→                <CheckCircle className="h-4 w-4" />
141→                <span>
142→                  {result.successful} session{result.successful !== 1 ? 's' : ''} analyzed successfully
143→                </span>
144→              </div>
145→              {result.failed > 0 && (
146→                <div className="space-y-1">
147→                  <div className="flex items-center gap-2 text-red-500">
148→                    <AlertCircle className="h-4 w-4" />
149→                    <span>{result.failed} failed</span>
150→                  </div>
151→                  <ul className="text-xs text-muted-foreground list-disc list-inside max-h-32 overflow-y-auto">
152→                    {result.errors.slice(0, 5).map((err, i) => (
153→                      <li key={i} className="truncate">{err}</li>
154→                    ))}
155→                    {result.errors.length > 5 && (
156→                      <li>...and {result.errors.length - 5} more</li>
157→                    )}
158→                  </ul>
159→                </div>
160→              )}
161→              <Button onClick={handleClose} className="w-full">
162→                Done
163→              </Button>
164→            </div>
165→          )}
166→        </div>
167→      </DialogContent>
168→    </Dialog>
169→  );
170→}
