 4→export function useAnalyzeSession() {
 5→  const queryClient = useQueryClient();
 6→  return useMutation({
 7→    mutationFn: (sessionId: string) => analyzeSession(sessionId),
 8→    onSuccess: (_data, sessionId) => {
 9→      // Invalidate insights and the session itself — analysis may produce new insights
10→      // and update session summary/title.
11→      queryClient.invalidateQueries({ queryKey: ['insights'] });
12→      queryClient.invalidateQueries({ queryKey: ['session', sessionId] });
13→    },
14→  });
15→}
